diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 8567a0504f54..f8444f97fa03 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1235,6 +1235,19 @@ static Value *simplifySRemInst(Value *Op0, Value *Op1, const SimplifyQuery &Q,
   if (isKnownNegation(Op0, Op1))
     return ConstantInt::getNullValue(Op0->getType());

+  Value *X;
+  const APInt *C1, *C2;
+  // srem (X * C1), (X * C2) -> X if C1 is min-signed-val and C2 is C1+1.
+  // Ex: srem (X * -128), (X * 127) -> X
+  if (match(Op0, m_Mul(m_Value(X), m_APInt(C1))) &&
+      match(Op1, m_Mul(m_Specific(X), m_APInt(C2))) && C1->isMinSignedValue() &&
+      *C2 == *C1 + 1) {
+    // We can't just return X because we need to replace the instruction.
+    // simplifyValue can do this, but we are in simplifySRemInst, so we can
+    // just return X and the caller will do the replacement.
+    return X;
+  }
+
   return simplifyRem(Instruction::SRem, Op0, Op1, Q, MaxRecurse);
 }

